import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  DateRangeFilter,
  Modal,
  Pagination,
  SearchTextInput,
  Select,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
  useErpListSelection,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherListFilterState } from '../../../hooks/useVoucherListFilterState';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import { sanPhamHoanThanhPageLabels as labels } from '../../../constants/sanPhamHoanThanhPageLabels';
import { sxService } from '../../../services/sx/sxService';
import type { StageTrackingDto } from '../../../services/sx/models';
import { formatDateLocal, formatNumber } from '../../../utils/format';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { ListUiSchemaEditorModal } from '../../../components/listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';
import { useMesCompletionQcPermissions } from '../../../hooks/useMesPermissions';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-san-pham-hoan-thanh';
const PAGE_ID = 'sx-san-pham-hoan-thanh';
const CATALOG_KIND = LIST_UI_SCHEMA_KIND.mesStageTracking;
const showSchemaConfig = true;
const PAGE_SIZE = 50;

const STATUS_OPTIONS = [
  { value: '', label: labels.statusAll },
  { value: 'Pending', label: labels.statusPending },
  { value: 'QcApproved', label: labels.statusApproved },
  { value: 'QcRejected', label: labels.statusRejected },
];

const TRACKING_STATUS: Record<string, string> = {
  Pending: labels.statusPending,
  QcApproved: labels.statusApproved,
  QcRejected: labels.statusRejected,
};

function statusTagClass(status: string): string {
  if (status === 'QcApproved') return erp.tagSuccess;
  if (status === 'QcRejected') return erp.tagError;
  return erp.tagWarning;
}

const SanPhamHoanThanhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const perms = useMesCompletionQcPermissions();
  const [reloadKey, setReloadKey] = useState(0);
  const [rows, setRows] = useState<StageTrackingDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [rejectOpen, setRejectOpen] = useState(false);
  const [target, setTarget] = useState<StageTrackingDto | null>(null);
  const [rejectReason, setRejectReason] = useState('');
  const [actionId, setActionId] = useState<string | null>(null);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);

  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    status,
    setStatus,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.sanPhamHoanThanh);

  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const selection = useErpListSelection({
    rows,
    totalCount,
    page,
    pageSize: PAGE_SIZE,
    getRowId: r => r.id,
  });

  const refresh = useCallback(() => {
    selection.clearActiveRow();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = useCallback(() => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearActiveRow();
      setReloadKey(k => k + 1);
    });
  }, [pulseSearch, searchDraft, setSearch, setPage, selection]);

  useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getStageTracking({
          fromDate: fromDate || undefined,
          toDate: toDate || undefined,
          status: status || undefined,
          searchText: search || undefined,
          page,
          pageSize: PAGE_SIZE,
        })
        .then(res => {
          if (!cancelled) {
            setRows(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, labels.loadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [initialized, fromDate, toDate, status, page, search, reloadKey, dispatch]);

  const handleApprove = async (id: string) => {
    setActionId(id);
    try {
      await sxService.qcApproveStageTracking(id);
      dispatchAppToast(dispatch, { message: labels.approveSuccess, type: 'success' });
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.approveError),
        type: 'error',
      });
    } finally {
      setActionId(null);
    }
  };

  const openReject = useCallback((row: StageTrackingDto) => {
    setTarget(row);
    setRejectReason('');
    setRejectOpen(true);
  }, []);

  const handleReject = async () => {
    if (!target || !rejectReason.trim()) {
      dispatchAppToast(dispatch, { message: labels.rejectReasonRequired, type: 'error' });
      return;
    }
    setActionId(target.id);
    try {
      await sxService.qcRejectStageTracking(target.id, rejectReason.trim());
      dispatchAppToast(dispatch, { message: labels.rejectSuccess, type: 'success' });
      setRejectOpen(false);
      setRejectReason('');
      refresh();
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, labels.rejectError),
        type: 'error',
      });
    } finally {
      setActionId(null);
    }
  };

  const totalOut = rows.reduce((a, r) => a + r.outQty, 0);
  const totalDefect = rows.reduce((a, r) => a + r.defectQty, 0);
  const pending = rows.filter(r => r.status === 'Pending').length;

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: refresh,
      canView: false,
      canEdit: false,
      canCreate: false,
      ...(showSchemaConfig ? { onEditConfig: () => setShowSchemaEditor(true) } : {}),
    }),
    [refresh],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            placeholder={labels.searchPlaceholder}
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            testId={`${TEST_ID}-search-text`}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${TEST_ID}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
              setReloadKey(k => k + 1);
            }}
          />
        ),
      },
      {
        testId: `${TEST_ID}-field-status`,
        content: (
          <Select
            label={labels.colStatus}
            value={status}
            onChange={e => {
              setStatus(e.target.value);
              resetPage();
              setReloadKey(k => k + 1);
            }}
            options={STATUS_OPTIONS}
            fullWidth
          />
        ),
      },
    ],
    [
      searchDraft,
      handleSearch,
      fromDate,
      toDate,
      datePreset,
      status,
      applyDateRange,
      resetPage,
      setStatus,
    ],
  );

  const listBody =
    !showTableLoading && rows.length === 0 ? (
      <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>
        <i className="fas fa-inbox" />
        <p>{labels.empty}</p>
      </div>
    ) : !showTableLoading ? (
      <div className={erp.tableWrapper}>
        <table className={erp.table} data-testid={`${TEST_ID}-table`}>
          <thead>
            <tr>
              <th>{labels.colDate}</th>
              <th>{labels.colLsx}</th>
              <th>{labels.colStage}</th>
              <th className={erp.colRight}>{labels.colOutQty}</th>
              <th className={erp.colRight}>{labels.colDefectQty}</th>
              <th>{labels.colStatus}</th>
              <th className={erp.colActions} />
            </tr>
          </thead>
          <tbody>
            {rows.map(r => (
              <tr
                key={r.id}
                data-testid={`${TEST_ID}-row-${r.id}`}
                className={
                  selection.activeRow?.id === r.id
                    ? erp.rowSelected
                    : r.status === 'Pending'
                      ? erp.rowDanger
                      : undefined
                }
                onClick={() => selection.selectActiveRow(r)}
              >
                <td>{formatDateLocal(r.trackingDate)}</td>
                <td>
                  <code>{r.productionOrderCode}</code>
                </td>
                <td>{r.stageName}</td>
                <td className={erp.colRight}>{formatNumber(r.outQty)}</td>
                <td className={erp.colRight}>{formatNumber(r.defectQty)}</td>
                <td>
                  <span className={statusTagClass(r.status)}>
                    {TRACKING_STATUS[r.status] ?? r.status}
                  </span>
                </td>
                <td className={erp.colActions}>
                  {r.status === 'Pending' && (perms.canApprove || perms.canReject) && (
                    <>
                      {perms.canApprove && (
                      <button
                        type="button"
                        className={erp.actionBtn}
                        disabled={actionId === r.id}
                        onClick={e => {
                          e.stopPropagation();
                          handleApprove(r.id);
                        }}
                        title="Duyệt"
                        data-testid={`${TEST_ID}-approve-${r.id}`}
                      >
                        <i className="fas fa-check" />
                      </button>
                      )}
                      {perms.canReject && (
                      <button
                        type="button"
                        className={`${erp.actionBtn} ${erp.actionBtnDanger}`}
                        onClick={e => {
                          e.stopPropagation();
                          openReject(r);
                        }}
                        title="Từ chối"
                        data-testid={`${TEST_ID}-reject-${r.id}`}
                      >
                        <i className="fas fa-times" />
                      </button>
                      )}
                    </>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-kind={CATALOG_KIND}
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.listTitle,
          titleIconClass: 'fas fa-check-circle',
          pageId: PAGE_ID,
        }}
        voucherToolbar={voucherToolbar}
        listTitle={labels.listSubtitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={8}
        footer={
          totalCount > 0 || rows.length > 0 ? (
            <div className={erp.paginationRow}>
              <span className={erp.summaryItem}>
                {labels.summaryOut}: <strong>{formatNumber(totalOut)}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryDefect}: <strong>{formatNumber(totalDefect)}</strong>
              </span>
              <span className={erp.summaryItem}>
                {labels.summaryPending}: <strong>{pending}</strong>
              </span>
              {totalCount > PAGE_SIZE ? (
                <>
                  <span className={erp.totalCount}>Tổng: {totalCount} phiếu</span>
                  <Pagination
                    currentPage={page}
                    totalPages={Math.ceil(totalCount / PAGE_SIZE)}
                    totalCount={totalCount}
                    pageSize={PAGE_SIZE}
                    onPageChange={p => {
                      setPage(p);
                      selection.clearActiveRow();
                    }}
                  />
                </>
              ) : (
                <span className={erp.totalCount}>Tổng: {totalCount} phiếu</span>
              )}
            </div>
          ) : undefined
        }
        modals={
          <>
            {showSchemaConfig ? (
              <ListUiSchemaEditorModal
                testIdPrefix={TEST_ID}
                catalogKind={CATALOG_KIND}
                isOpen={showSchemaEditor}
                onClose={() => setShowSchemaEditor(false)}
                onSaved={() => refresh()}
                sampleRow={rows[0] as unknown as Record<string, unknown>}
              />
            ) : null}
            <Modal
            isOpen={rejectOpen}
            onClose={() => setRejectOpen(false)}
            title={labels.rejectModalTitle}
          >
            <div className={erp.modalBody}>
              <p>
                LSX: <b>{target?.productionOrderCode}</b> — {target?.stageName}
              </p>
              <div className={erp.field}>
                <label className={erp.label}>{labels.rejectReasonLabel} *</label>
                <textarea
                  value={rejectReason}
                  onChange={e => setRejectReason(e.target.value)}
                  rows={3}
                  data-testid={`${TEST_ID}-reject-reason`}
                />
              </div>
            </div>
            <div className={erp.modalActions}>
              <Button variant="secondary" onClick={() => setRejectOpen(false)}>
                Huỷ
              </Button>
              <Button
                variant="primary"
                onClick={handleReject}
                disabled={actionId === target?.id}
                data-testid={`${TEST_ID}-reject-confirm`}
              >
                Từ chối
              </Button>
            </div>
          </Modal>
          </>
        }
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default SanPhamHoanThanhPage;
